import { useEffect, useState } from "react";
import { statsApi } from "../services/api";
import MapView from "../components/MapView";

const Home = () => {
  const [stats, setStats] = useState([]);

  useEffect(() => {
    statsApi.list().then((res) => setStats(res.data.data || [])).catch(() => setStats([]));
  }, []);

  const nbAnnonces = stats.reduce((acc, s) => acc + (s.nombre_annonces || 0), 0);
  const nbZones = new Set(stats.map((s) => s.zone)).size;
  const prixMoy = stats.length ? stats.reduce((a, b) => a + (b.prix_moyen_m2 || 0), 0) / stats.length : 0;

  return (
    <div className="space-y-8">
      <section className="bg-gradient-to-r from-primary to-cyan-500 text-white p-8 rounded-2xl">
        <h1 className="text-3xl font-bold">ID Immobilier</h1>
        <p className="mt-2">La donnée immobilière fiable pour Lomé.</p>
      </section>

      <section className="grid md:grid-cols-3 gap-4">
        <div className="bg-white p-4 rounded-xl shadow">Annonces: <strong>{nbAnnonces}</strong></div>
        <div className="bg-white p-4 rounded-xl shadow">Zones: <strong>{nbZones}</strong></div>
        <div className="bg-white p-4 rounded-xl shadow">Prix moyen: <strong>{prixMoy.toFixed(0)} FCFA/m²</strong></div>
      </section>

      <MapView points={stats.map((s) => ({ zone: s.zone, prix: s.prix_moyen_m2 }))} />
    </div>
  );
};

export default Home;
